<?php

use common\logic\Helper\Price;
use Common_Model_Eshop as EshopModel;
use common\logic\Eshop\Eshop;
use common\logic\Languages;
use user\logic\UserClientSession;

/**
 * Admin_Model_Coupon
 *
 * This class has been auto-generated by the Doctrine ORM Framework
 *
 * @package    ##PACKAGE##
 * @subpackage ##SUBPACKAGE##
 * @author     ##NAME## <##EMAIL##>
 * @version    SVN: $Id: Builder.php 7490 2010-03-29 19:53:27Z jwage $
 */
class Admin_Model_Coupon extends Admin_Model_Base_Coupon {

    const TYPE_ITEM = "item";
    const TYPE_DISCOUNT = "discount";
    const TYPE_PERCENTAGE = "percentage";

    /**
     * @param Doctrine_Connection|null $conn
     * @throws Exception
     */
    public function save(Doctrine_Connection $conn = null) {
        if ($this->ID == null) {
            $this->CreatedDate = date('Y-m-d');
            $this->UsedCount = 0;
            if ($this->TotalCount < 0)
                $this->TotalCount = 0;
        }

        parent::save($conn);
    }

    /**
     * @return array
     */
    public static function getCouponTypes(): array {
        return [
            self::TYPE_PERCENTAGE => translate('Sleva') . ' (' . translate('procentuální') . ')',
            self::TYPE_DISCOUNT => translate('Sleva') . ' (' . translate('částka') . ')',
            self::TYPE_ITEM => translate('Produkt zdarma'),
        ];
    }

    /**
     * @param string $code
     * @param int|float|null $order
     * @return self|null|false
     */
    public static function getCouponByCode(string $code, $order = null) {
        $User_ID = UserClientSession::getCurrentUserID();
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Coupon object');
        $query->where('object.Code = ?', $code);
        $query->andWhere('object.ExpiryDate > NOW()');
        $query->andWhere('IFNULL(object.TotalCount, 0) < 1 OR object.UsedCount < object.TotalCount');

        if ($User_ID)
            $query->andWhere('object.User_ID IS NULL OR object.User_ID = ?', $User_ID);
        else
            $query->andWhere('object.User_ID IS NULL');

        if (is_numeric($order)) {
            $query->andWhere('IFNULL(object.MinOrder, 0) < ?', $order);
        }

        return $query->fetchOne();
    }

    public function use() {
        $this->UsedCount++;
        $this->save();
    }

    /**
     * @param $orderID
     * @return self|null|false
     */
    public static function getCouponByOrder($orderID) {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Order object');
        $query->where('object.ID = ?', $orderID);
        $order = $query->execute()->toArray();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Coupon object');
        $query->where('object.ID = ?', $order[0]['Coupon_ID']);
        return $query->fetchOne();
    }

    /**
     * Vrací "slevu"
     * @param bool $withoutVat
     * @param bool $total
     * @return string
     */
    public function getDiscount(bool $withoutVat = false, bool $total = false, ?EshopModel $eshop = null): string {
        $currency = Admin_Model_Currency::getCurrentCurrency();
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        if ($withoutVat)
            $coef = ((100 + (int) $eshop->vat->Value) / 100);
        else
            $coef = 1;

        if ($total)
            $discount = $this->Discount * $this->Quantity;
        else
            $discount = $this->Discount;

        if ($this->Type === self::TYPE_ITEM)
            return price(0);

        if ($this->Type === self::TYPE_DISCOUNT)
            return price(Price::computeCouponCurrency((-($discount / $coef))), $currency['Label']);

        return number_format(-($discount), 0, '.', ' ') . '%';
    }

    /**
     * @return string
     * @throws Doctrine_Query_Exception
     */
    public function getName() {
        if ($this->Type === self::TYPE_ITEM)
            return $this->product->getLang(Languages::getLangID())->Name;

        return $name = $this->getLang(Languages::getLangID())->Name;
    }

    /**
     * @return bool
     */
    public function IsDiscount(): bool {
        return in_array($this->Type, [
            self::TYPE_DISCOUNT,
            self::TYPE_PERCENTAGE
        ]);
    }
}